311→          {
312→            type: 'paragraph',
313→            children: [
314→              {
315→                type: 'text',
316→                text: payload.plainText,
317→                detail: 0,
318→                format: 0,
319→                mode: 'normal',
320→                style: '',
321→                version: 1,
322→              },
323→            ],
324→            direction: null,
325→            format: '',
326→            indent: 0,
327→            version: 1,
