 27→export function ProfileWritingsTab({userId, headerComponent}: ProfileWritingsTabProps) {
 28→  const navigation = useNavigation<NativeStackNavigationProp<RootStackParamList>>();
 29→  const {session} = useAuth();
 30→  const token = session?.access_token ?? '';
 31→
