 21→export function ProfileStoriesTab({userId, headerComponent}: ProfileStoriesTabProps) {
 22→  const navigation = useNavigation<NativeStackNavigationProp<RootStackParamList>>();
 23→  const {session} = useAuth();
 24→  const token = session?.access_token;
 25→
 26→  const query = useInfiniteQuery({
