 29→      storyApi.getUserStories(userId, token ?? undefined, {
 30→        limit: PAGE_SIZE,
 31→        before: pageParam ?? null,
 32→      }),
 33→    initialPageParam: null as string | null,
 34→    getNextPageParam: lastPage => {
 35→      if (!lastPage.hasMore || lastPage.data.length < PAGE_SIZE) return undefined;
 36→      const last = lastPage.data[lastPage.data.length - 1];
 37→      return last?.created_at ?? undefined;
 38→    },
 39→  });
 40→
 41→  const stories = useMemo(
 42→    () => query.data?.pages.flatMap(page => page.data ?? []) ?? [],
 43→    [query.data?.pages],
 44→  );
 45→
 46→  return (
 47→    <FlatList
 48→      data={stories}
 49→      keyExtractor={item => item.id}
 50→      showsVerticalScrollIndicator={false}
 51→      contentContainerStyle={styles.list}
 52→      ListHeaderComponent={headerComponent}
 53→      onEndReachedThreshold={0.3}
