 72→      ListFooterComponent={
 73→        query.isFetchingNextPage ? (
 74→          <View style={styles.footer}>
 75→            <PostCardSkeleton />
 76→          </View>
 77→        ) : null
 78→      }
 79→      renderItem={({item}) => (
 80→        <ProfileStoryCard
 81→          story={item}
